const sgMail = require('@sendgrid/mail');
const twilio = require('twilio');

// IMPORTANT: For production, move these API keys to Azure Application Settings or Key Vault references.
// This setup is only for local development convenience.
const SENDGRID_API_KEY = 'SG.azure_demo_key_123';
const TWILIO_ACCOUNT_SID = 'AC1234567890abcdef';
const TWILIO_AUTH_TOKEN = 'your_twilio_auth_token_here'; // Placeholder: Replace with your actual Twilio Auth Token
const TWILIO_FROM_NUMBER = '+15017122661'; // Placeholder: Replace with your Twilio Phone Number (e.g., +1234567890)

sgMail.setApiKey(SENDGRID_API_KEY);

module.exports = async function (context, req) {
    context.log('HTTP trigger function processed a request.');

    const requestBody = req.body;

    if (!requestBody || !requestBody.type) {
        context.res = {
            status: 400,
            body: "Please pass a 'type' (email or sms) in the request body along with relevant data."
        };
        return;
    }

    if (requestBody.type === 'email') {
        const emailData = requestBody.email;
        if (!emailData || !emailData.to || !emailData.from || !emailData.subject || (!emailData.text && !emailData.html)) {
            context.res = {
                status: 400,
                body: "For email, please provide 'to', 'from', 'subject', and either 'text' or 'html' in the 'email' object."
            };
            return;
        }

        try {
            const msg = {
                to: emailData.to,
                from: emailData.from,
                subject: emailData.subject,
                text: emailData.text,
                html: emailData.html,
            };
            await sgMail.send(msg);
            context.log('Email sent successfully.');
            context.res = {
                status: 200,
                body: "Email sent successfully!"
            };
        } catch (error) {
            context.log.error('Error sending email:', error.response ? error.response.body : error.message);
            context.res = {
                status: 500,
                body: `Failed to send email: ${error.response && error.response.body && error.response.body.errors ? error.response.body.errors[0].message : error.message}`
            };
        }
    } else if (requestBody.type === 'sms') {
        const smsData = requestBody.sms;
        if (!smsData || !smsData.to || !smsData.body) {
            context.res = {
                status: 400,
                body: "For SMS, please provide 'to' (e.g., +1234567890) and 'body' in the 'sms' object."
            };
            return;
        }

        try {
            if (!TWILIO_FROM_NUMBER || TWILIO_FROM_NUMBER === '+15017122661') {
                 context.res = {
                    status: 500,
                    body: "Twilio 'from' number is not configured. Please update TWILIO_FROM_NUMBER."
                };
                return;
            }
            if (!TWILIO_AUTH_TOKEN || TWILIO_AUTH_TOKEN === 'your_twilio_auth_token_here') {
                 context.res = {
                    status: 500,
                    body: "Twilio Auth Token is not configured. Please update TWILIO_AUTH_TOKEN."
                };
                return;
            }

            const client = new twilio(TWILIO_ACCOUNT_SID, TWILIO_AUTH_TOKEN);
            const message = await client.messages.create({
                body: smsData.body,
                to: smsData.to,
                from: TWILIO_FROM_NUMBER,
            });
            context.log('SMS sent successfully. Message SID:', message.sid);
            context.res = {
                status: 200,
                body: `SMS sent successfully! Message SID: ${message.sid}`
            };
        } catch (error) {
            context.log.error('Error sending SMS:', error.message);
            context.res = {
                status: 500,
                body: `Failed to send SMS: ${error.message}`
            };
        }
    } else {
        context.res = {
            status: 400,
            body: "Invalid 'type' specified. Must be 'email' or 'sms'."
        };
    }
};